text:
{
  "formal_minutes": {
    "decisions": [
      {
        "항목": "공개 릴리스 대상일",
        "내용": "스모크 테스트 통과 시 금요일 15:00 KST를 공개 릴리스 목표로 확정."
      },
      {
        "항목": "packageName mismatch 처리 원칙",
        "내용": "smoke-theme-pack.mjs에서 packageName 불일치 시 무시 처리하지 않고, 먼저 패키지 설정을 확인한다. 계약(컴포넌트/요구사항) 자체가 잘못된 경우에만 스크립트를 검토한다."
      },
      {
        "항목": "재실행 및 산출 공유",
        "내용": "Minjun이 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다."
      },
      {
        "항목": "실패 트리아지 기록",
        "내용": "Doyun이 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다."
      },
      {
        "항목": "릴리스 패키지 산출물 검증",
        "내용": "Hara가 Minjun의 스모크 테스트 결과 공유 후 생성된 tarball 경로를 확인한다."
      }
    ],
    "rejected_proposals": [
      {
        "항목": "제안 거부",
        "내용": "Hara가 제안한 'smoke-theme-pack.mjs에서 packageName mismatch 무시 처리' 제안은 회의에서 반려."
      }
    ],
    "non_decisions": [
      {
        "항목": "README 설치 안내 검토 소유자",
        "내용": "README 설치 절차 검토는 진행 필요성이 제시되었으나, 소유자/책임주체가 확정되지 않음."
      }
    ],
    "internal_stretch_goals": [
      {
        "항목": "수요일 목표",
        "내용": "Seoyeon의 수요일 공개 릴리스 제안은 내부 stretch goal로만 언급되었고, 최종 일정으로 확정되지 않음."
      }
    ],
    "risks": [
      {
        "항목": "tarball 경로 오류",
        "내용": "생성된 tarball 경로가 잘못되면 릴리스 지연 가능성 존재."
      },
      {
        "항목": "README 안내 부정합",
        "내용": "README 설치 단계가 최신 상태가 아니면 릴리스 노트/안내가 사용자 오도 가능성."
      }
    ],
    "open_questions": [
      {
        "항목": "최종 릴리스 승인 권한",
        "내용": "최종 공개 릴리스 승인 권한자는 현재 미정."
      },
      {
        "항목": "수요일 stretch goal 공개 여부",
        "내용": "릴리스 노트에 내부 수요일 목표를 언급할지 여부가 미결정."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 테스트 공유 후 생성 tarball 경로 확인",
      "due": "미정(결과 공유 후)",
      "status": "대기",
      "source_certainty": "high"
    },
    {
      "owner": "미정",
      "task": "README install 단계 최신화 여부 검토 (가능하면 목요일까지)",
      "due": "목요일(가능하면) / 미정",
      "status": "요청됨",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 전까지 스모크 테스트 결과 공유 여부",
      "스모크 실패 시 Doyun의 action_items.md 트리아지 노트 작성 완료 여부",
      "Minjun 결과 공유 후 Hara의 tarball 경로 확인 완료 여부",
      "최종 릴리스 승인 권한자 지정 필요(미결정 항목 해결)",
      "릴리스 노트에 수요일 내부 stretch goal 기재 여부 결정"
    ],
    "what_not_to_invent": [
      "고객명, 협력사, 예산, 보안 사고, 장애, 법무 승인 요건 등의 미언급 사실",
      "소유자 미지정 항목의 담당자 또는 임의 마감시간",
      "실제 공개 릴리스 승인자, 법적 판단, 재무/보안/운영 제약 조건"
    ]
  },
  "non_invention_rules": [
    "회의록 본문과 명시적 Raw notes에 없는 고정 사실은 추론으로 추가하지 않는다.",
    "참여자, 시간, 결정, 리스크, 질문은 입력된 fixture에서만 사용한다.",
    "customer/partner, budget, security incident, outage, legal approval, owner 미확정 항목, deadline 미기재 항목은 생성하지 않는다.",
    "제안/반려/확정/보류의 구분을 유지하고, stretch goal(수요일)은 공개 일정으로 오인하지 않는다."
  ]
}
